72	// beadAutoCommit commits .ddx/beads.jsonl if git.auto_commit is "always".
73	// The operation string describes what happened (e.g. "create ddx-abc123").
74	// Errors are silently ignored — auto-commit is best-effort.
75	// When a commit lands, the resulting SHA is returned.
76	func (f *CommandFactory) beadAutoCommit(operation string) string {
77		workspaceRoot := f.beadWorkspaceRoot()
78		if workspaceRoot == "" {
79			workspaceRoot = f.WorkingDir
80		}
81	
82		cfg, err := config.LoadWithWorkingDir(workspaceRoot)
83		if err != nil {
84			return ""
85		}
86		if cfg.Git == nil {
87			return ""
88		}
89		acCfg := gitpkg.AutoCommitConfig{
90			AutoCommit:   cfg.Git.AutoCommit,
91			CommitPrefix: cfg.Git.CommitPrefix,
92		}
93		beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
94		sha, _ := gitpkg.AutoCommit(beadsFile, "beads", operation, acCfg)
95		return sha
96	}
