98	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
99		if commitSHA == "" {
100			return "", nil
101		}
102	
103		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
104		defer cancel()
105	
106		repoDir := f.WorkingDir
107		if repoDir == "" {
108			repoDir = "."
109		}
110	
111		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
112			return commitSHA, nil
113		}
114	
115		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
116		out, err := cmd.Output()
117		if err != nil {
118			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
119		}
120		return strings.TrimSpace(string(out)), nil
121	}
122	
123	func isFullCommitSHA(commitSHA string) bool {
124		if len(commitSHA) != 40 {
125			return false
126		}
127		for i := 0; i < len(commitSHA); i++ {
128			c := commitSHA[i]
129			if c >= '0' && c <= '9' {
130				continue
131			}
132			if c >= 'a' && c <= 'f' {
133				continue
134			}
135			if c >= 'A' && c <= 'F' {
136				continue
137			}
138			return false
139		}
140		return true
141	}
