143	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
144		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
145		if err != nil {
146			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
147		}
148		if normalizedCommitSHA == "" {
149			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
150		}
151		return normalizedCommitSHA, nil
152	}
