154	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
155	// only bead tracker state. Closing provenance is suppressed only for pure
156	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
157	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
158		if commitSHA == "" {
159			return false
160		}
161	
162		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
163		defer cancel()
164	
165		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
166		out, err := cmd.Output()
167		if err != nil {
168			return false
169		}
170	
171		for _, line := range strings.Split(string(out), "\n") {
172			path := strings.TrimSpace(line)
173			if path == "" {
174				continue
175			}
176			if path != ".ddx/beads.jsonl" {
177				return false
178			}
179		}
180	
181		return true
182	}
