184	func isReviewCloseBead(b *bead.Bead) bool {
185		if b == nil {
186			return false
187		}
188		for _, label := range b.Labels {
189			switch label {
190			case "action:review", "kind:review", "phase:review", "review-finding":
191				return true
192			}
193		}
194		return false
195	}
