197	func (f *CommandFactory) beadWorkspaceRoot() string {
198		dir := os.Getenv("DDX_BEAD_DIR")
199		if dir != "" {
200			if filepath.Base(dir) == ".ddx" {
201				return filepath.Dir(dir)
202			}
203			return dir
204		}
205		if f.WorkingDir == "" {
206			return ""
207		}
208		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
209			return workspaceRoot
210		}
211		return f.WorkingDir
212	}
