313	func (f *CommandFactory) newBeadShowCommand() *cobra.Command {
314		cmd := &cobra.Command{
315			Use:   "show <id>",
316			Short: "Show a bead",
317			Args:  cobra.ExactArgs(1),
318			RunE: func(cmd *cobra.Command, args []string) error {
319				s := f.beadStore()
320				b, err := s.GetWithArchive(args[0])
321				if err != nil {
322					return err
323				}
324	
325				asJSON, _ := cmd.Flags().GetBool("json")
326				if asJSON {
327					// Externalized events live in a sidecar; inline them for the
328					// JSON view so consumers (and the `events` UI projection)
329					// see a single uniform shape.
330					if err := s.LoadEventsInline(b); err != nil {
331						return err
332					}
333					data, err := bead.MarshalBead(*b)
334					if err != nil {
335						return err
336					}
337					var obj map[string]any
338					if err := json.Unmarshal(data, &obj); err != nil {
339						return err
340					}
341					workspaceRoot := f.beadWorkspaceRoot()
342					if workspaceRoot == "" {
343						workspaceRoot = f.WorkingDir
344					}
345					metrics, err := beadMetricsFor(workspaceRoot, b.ID)
346					if err != nil {
347						return err
348					}
349					if metrics == nil {
350						metrics = &beadMetricsSummary{}
351					}
352					obj["metrics"] = metrics
353					enc := json.NewEncoder(cmd.OutOrStdout())
354					enc.SetIndent("", "  ")
355					return enc.Encode(obj)
356				}
357	
358				out := cmd.OutOrStdout()
359				fmt.Fprintf(out, "ID:       %s\n", b.ID)
360				fmt.Fprintf(out, "Title:    %s\n", b.Title)
361				fmt.Fprintf(out, "Type:     %s\n", b.IssueType)
362				fmt.Fprintf(out, "Status:   %s\n", b.Status)
363				fmt.Fprintf(out, "Priority: %d\n", b.Priority)
364				if len(b.Labels) > 0 {
365					fmt.Fprintf(out, "Labels:   %s\n", strings.Join(b.Labels, ", "))
366				}
367				if b.Owner != "" {
368					fmt.Fprintf(out, "Owner:    %s\n", b.Owner)
369				}
370				if b.Parent != "" {
371					fmt.Fprintf(out, "Parent:   %s\n", b.Parent)
372				}
373				if len(b.Dependencies) > 0 {
374					fmt.Fprintf(out, "Deps:     %s\n", strings.Join(b.DepIDs(), ", "))
375				}
376				if b.Description != "" {
377					fmt.Fprintf(out, "Desc:     %s\n", b.Description)
378				}
379				if b.Acceptance != "" {
380					fmt.Fprintf(out, "Accept:   %s\n", b.Acceptance)
381				}
382				fmt.Fprintf(out, "Created:  %s\n", b.CreatedAt.Format("2006-01-02 15:04:05"))
383				fmt.Fprintf(out, "Updated:  %s\n", b.UpdatedAt.Format("2006-01-02 15:04:05"))
384				// Show agent session evidence if present
385				if b.Extra != nil {
386					if sessionID, ok := b.Extra["session_id"]; ok && sessionID != "" {
387						fmt.Fprintf(out, "Session:  %v\n", sessionID)
388						// Try to resolve session details
389						if sess := f.resolveAgentSession(fmt.Sprint(sessionID)); sess != nil {
390							fmt.Fprintf(out, "Harness:  %s\n", sess.Harness)
391							if sess.Model != "" {
392								fmt.Fprintf(out, "Model:    %s\n", sess.Model)
393							}
394							if sess.Tokens > 0 {
395								fmt.Fprintf(out, "Tokens:   %d (in: %d, out: %d)\n", sess.Tokens, sess.InputTokens, sess.OutputTokens)
396							}
397							if sess.CostUSD > 0 {
398								fmt.Fprintf(out, "Cost:     $%.4f\n", sess.CostUSD)
399							}
400							if sess.Duration > 0 {
401								fmt.Fprintf(out, "Duration: %dms\n", sess.Duration)
402							}
403						}
404					}
405					if commitSHA, ok := b.Extra["closing_commit_sha"]; ok && commitSHA != "" {
406						fmt.Fprintf(out, "Commit:   %v\n", commitSHA)
407					}
408					if v, ok := b.Extra["claimed-at"]; ok {
409						fmt.Fprintf(out, "Claimed:  %v\n", v)
410					}
411					if v, ok := b.Extra["claimed-machine"]; ok {
412						fmt.Fprintf(out, "Machine:  %v\n", v)
413					}
414					if v, ok := b.Extra["claimed-session"]; ok {
415						fmt.Fprintf(out, "Session:  %v\n", v)
416					}
417					if v, ok := b.Extra["claimed-worktree"]; ok {
418						fmt.Fprintf(out, "Worktree: %v\n", v)
419					}
420				}
421				claimKeys := map[string]bool{
422					"claimed-at": true, "claimed-pid": true,
423					"claimed-machine": true, "claimed-session": true, "claimed-worktree": true,
424					"session_id": true, "closing_commit_sha": true,
425				}
426				for k, v := range b.Extra {
427					if !claimKeys[k] {
428						fmt.Fprintf(out, "%s: %v\n", k, v)
429					}
430				}
431				return nil
432			},
433		}
434		cmd.Flags().Bool("json", false, "Output as JSON")
435		return cmd
436	}
