438	func (f *CommandFactory) newBeadUpdateCommand() *cobra.Command {
439		cmd := &cobra.Command{
440			Use:   "update <id>",
441			Short: "Update a bead",
442			Args:  cobra.ExactArgs(1),
443			RunE: func(cmd *cobra.Command, args []string) error {
444				s := f.beadStore()
445	
446				// --claim and --unclaim use dedicated store methods
447				if claim, _ := cmd.Flags().GetBool("claim"); claim {
448					assignee, _ := cmd.Flags().GetString("assignee")
449					if assignee == "" {
450						assignee = resolveClaimAssignee()
451					}
452					if err := s.Claim(args[0], assignee); err != nil {
453						return err
454					}
455					f.beadAutoCommit("claim " + args[0])
456					return nil
457				}
458				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
459					if err := s.Unclaim(args[0]); err != nil {
460						return err
461					}
462					f.beadAutoCommit("unclaim " + args[0])
463					return nil
464				}
465	
466				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
467					for _, key := range unsetFlags {
468						if isProtectedBeadExtraKey(key) {
469							return fmt.Errorf("cannot unset protected bead field: %s", key)
470						}
471					}
472				}
473	
474				var setFlags []string
475				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
476					setFlags = make([]string, 0, len(rawSetFlags))
477					for _, kv := range rawSetFlags {
478						k, v, ok := strings.Cut(kv, "=")
479						if !ok {
480							return fmt.Errorf("--set requires key=value format, got: %s", kv)
481						}
482						if k == "closing_commit_sha" {
483							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
484							if err != nil {
485								return err
486							}
487							v = normalizedCommitSHA
488						}
489						setFlags = append(setFlags, k+"="+v)
490					}
491				}
492	
493				if err := s.Update(args[0], func(b *bead.Bead) {
494					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
495						b.Title = v
496					}
497					if v, _ := cmd.Flags().GetString("status"); cmd.Flags().Changed("status") {
498						b.Status = v
499					}
500					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
501						b.Priority = v
502					}
503					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
504						if v == "" {
505							b.Labels = []string{}
506						} else {
507							b.Labels = strings.Split(v, ",")
508						}
509					}
510					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
511						b.Acceptance = v
512					}
513					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
514						b.Owner = v
515					}
516					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
517						b.Parent = v
518					}
519					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
520						b.Description = v
521					}
522					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
523						b.Notes = v
524					}
525					if len(setFlags) > 0 {
526						if b.Extra == nil {
527							b.Extra = make(map[string]any)
528						}
529						for _, kv := range setFlags {
530							k, v, ok := strings.Cut(kv, "=")
531							if !ok {
532								continue
533							}
534							// Route known field names to struct fields
535							switch k {
536							case "parent":
537								b.Parent = v
538							case "description":
539								b.Description = v
540							case "notes":
541								b.Notes = v
542							case "acceptance":
543								b.Acceptance = v
544							case "issue_type":
545								b.IssueType = v
546							default:
547								// Parse booleans and numbers for proper typing
548								switch v {
549								case "true":
550									b.Extra[k] = true
551								case "false":
552									b.Extra[k] = false
553								default:
554									b.Extra[k] = v
555								}
556							}
557						}
558					}
559					if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
560						for _, key := range unsetFlags {
561							if b.Extra != nil {
562								delete(b.Extra, key)
563							}
564						}
565					}
566				}); err != nil {
567					return err
568				}
569				f.beadAutoCommit("update " + args[0])
570				return nil
571			},
572		}
