591	func resolveClaimAssignee() string {
592		for _, key := range []string{"DDX_AGENT_NAME", "USER", "LOGNAME", "USERNAME", "SUDO_USER"} {
593			if v := os.Getenv(key); v != "" {
594				return v
595			}
596		}
597		return "ddx"
598	}
