600	func isProtectedBeadExtraKey(key string) bool {
601		switch key {
602		case "events", "session_id", "claimed-at", "claimed-pid", "claimed-machine", "claimed-session", "claimed-worktree":
603			return true
604		default:
605			return false
606		}
