682	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
683		cmd := &cobra.Command{
684			Use:   "close <id>",
685			Short: "Close a bead",
686			Args:  cobra.ExactArgs(1),
687			RunE: func(cmd *cobra.Command, args []string) error {
688				s := f.beadStore()
689				sessionID, _ := cmd.Flags().GetString("session")
690				commitSHA, _ := cmd.Flags().GetString("commit")
691	
692				if commitSHA != "" {
693					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
694					if err != nil {
695						return err
696					}
697					commitSHA = normalizedCommitSHA
698				}
699	
700				target, err := s.Get(args[0])
701				if err != nil {
702					return err
703				}
704				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
705				// operator closes without evidence are intentionally a separate
706				// path. When --session and --commit are both unset, we are in
707				// manual-administration territory — use the ungated Store.Close
708				// so the gate doesn't reject legitimate tracker admin.
709				if sessionID == "" && commitSHA == "" {
710					if err := s.Close(args[0]); err != nil {
711						return err
712					}
713				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
714					return err
715				}
716	
717				landedSHA := f.beadAutoCommit("close " + args[0])
718				if commitSHA == "" && landedSHA != "" {
719					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
720						if isReviewCloseBead(target) {
721							// Tracker-only review-finding closes must not retain any prior
722							// replay boundary. The close commit itself is the metadata-only
723							// backfill, so clear stale closing provenance instead of
724							// preserving an unrelated implementation SHA.
725							if err := s.Update(args[0], func(b *bead.Bead) {
726								if b.Extra == nil {
727									return
728								}
729								delete(b.Extra, "closing_commit_sha")
730							}); err != nil {
731								return err
732							}
733							if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
734								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
735							}
736						}
737					} else {
738						// Only stamp closing provenance when the close commit includes
739						// real implementation work. Pure tracker backfills should not
740						// advertise a replay boundary that points at metadata-only
741						// provenance.
742						if err := s.Update(args[0], func(b *bead.Bead) {
743							if b.Extra == nil {
744								b.Extra = make(map[string]any)
745							}
746							b.Extra["closing_commit_sha"] = landedSHA
747						}); err != nil {
748							return err
749						}
750						if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
751							return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
752						}
753					}
754				}
755				return nil
756			},
757		}
758		cmd.Flags().String("session", "", "Agent session ID that completed this bead")
759		cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
760		return cmd
761	}
