1086	func (f *CommandFactory) newBeadMergeCommand() *cobra.Command {
1087		cmd := &cobra.Command{
1088			Use:   "merge [path]",
1089			Short: "Resolve a Git conflict in .ddx/beads.jsonl",
1090			Long: `Resolve a Git conflict in .ddx/beads.jsonl using DDx tracker rules.
1091	
1092	This is the supported escape hatch when Git leaves the bead tracker in an
1093	unmerged state. It reads the base, ours, and theirs versions from the Git
1094	index stages (:1:, :2:, :3:), merges records by bead id, preserves append-only
1095	events and dependency edges, writes the resolved JSONL file, and reports any
1096	scalar fields that required deterministic conflict resolution.
1097	
1098	This command is not a general hand-edit workflow for bead tracker data.`,
1099			Args: cobra.MaximumNArgs(1),
1100			RunE: func(cmd *cobra.Command, args []string) error {
1101				path := filepath.Join(".ddx", "beads.jsonl")
1102				if len(args) > 0 {
1103					path = args[0]
1104				}
1105				workspaceRoot := f.beadWorkspaceRoot()
1106				if workspaceRoot == "" {
1107					workspaceRoot = f.WorkingDir
1108				}
1109				repoRoot := gitpkg.FindProjectRoot(workspaceRoot)
1110				relPath, err := filepath.Rel(repoRoot, filepath.Join(workspaceRoot, path))
1111				if err != nil || strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
1112					relPath = filepath.ToSlash(path)
1113				}
1114				relPath = filepath.ToSlash(filepath.Clean(relPath))
1115	
1116				base, err := gitStageBlob(cmd.Context(), repoRoot, 1, relPath)
1117				if err != nil {
1118					return err
1119				}
1120				ours, err := gitStageBlob(cmd.Context(), repoRoot, 2, relPath)
1121				if err != nil {
1122					return err
1123				}
1124				theirs, err := gitStageBlob(cmd.Context(), repoRoot, 3, relPath)
1125				if err != nil {
1126					return err
1127				}
1128	
1129				merged, report, err := bead.MergeTrackerConflictJSONL(base, ours, theirs)
1130				if err != nil {
1131					return err
1132				}
1133				outPath := filepath.Join(repoRoot, relPath)
1134				if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
1135					return fmt.Errorf("bead merge: mkdir: %w", err)
1136				}
1137				if err := os.WriteFile(outPath, merged, 0o644); err != nil {
1138					return fmt.Errorf("bead merge: write %s: %w", relPath, err)
1139				}
1140	
1141				fmt.Fprintf(cmd.OutOrStdout(), "Merged %s: %d records (%d ours-only, %d theirs-only, %d same-id merged)\n",
1142					relPath, report.TotalRecords, report.PreservedOurs, report.PreservedTheirs, report.MergedRecords)
1143				for _, conflict := range report.ScalarConflicts {
1144					fmt.Fprintf(cmd.OutOrStdout(), "Resolved scalar conflict: %s.%s chose %s (%s)\n",
1145						conflict.ID, conflict.Field, conflict.Choice, conflict.Reason)
1146				}
1147				return nil
1148			},
1149		}
1150		return cmd
1151	}
