1153	func gitStageBlob(ctx context.Context, repoRoot string, stage int, path string) ([]byte, error) {
1154		spec := fmt.Sprintf(":%d:%s", stage, path)
1155		out, err := gitpkg.Command(ctx, repoRoot, "show", spec).Output()
1156		if err != nil {
1157			return nil, fmt.Errorf("bead merge: read Git stage %d for %s: %w", stage, path, err)
1158		}
1159		return out, nil
1160	}
