1162	// newBeadCooldownCommand wires `ddx bead cooldown show|clear <id>`.
1163	//
1164	// `cooldown show` prints the bead's current execute-loop cooldown fields
1165	// (retry-after, last-status, last-detail) in human or JSON form. `cooldown
1166	// clear` removes those three fields so the bead becomes execution-eligible
1167	// again at the next loop pass. This is the first-class operator-facing
1168	// surface for the underlying `execute-loop-retry-after` Extra key — the
1169	// `ddx bead update --set/--unset execute-loop-retry-after=...` workflow
1170	// continues to work as a power-user fallback, but operators should reach
1171	// for `cooldown clear` for the common case.
1172	func (f *CommandFactory) newBeadCooldownCommand() *cobra.Command {
1173		cmd := &cobra.Command{
1174			Use:   "cooldown",
1175			Short: "Inspect and clear execute-loop cooldowns",
1176			Long: `Inspect and clear the execute-loop cooldown that parks a bead from
1177	re-execution. Cooldowns are set automatically by the loop in three cases:
1178	
