93	// Applies reports whether the check should run for the given context.
94	func (c *Check) Applies(ctx InvocationContext) bool {
95		a := c.AppliesTo
96		if len(a.Paths) == 0 && len(a.Labels) == 0 {
97			return true
98		}
99		for _, lbl := range a.Labels {
100			for _, b := range ctx.BeadLabels {
101				if lbl == b {
102					return true
103				}
104			}
105		}
106		for _, glob := range a.Paths {
107			for _, p := range ctx.ChangedPaths {
108				if matched, _ := filepath.Match(glob, p); matched {
109					return true
110				}
111				// Also try matching against just the basename so
112				// patterns like "*.go" match deeply nested files.
113				if matched, _ := filepath.Match(glob, filepath.Base(p)); matched {
114					return true
115				}
116			}
117		}
118		return false
119	}
