161	func TestRun_ParallelExecution(t *testing.T) {
162		// Two checks that each sleep then write a unique file. Wall time
163		// should be close to one sleep, not two — verifying parallelism.
164		_, ictx := newCtx(t)
165		mk := func(name string) Check {
166			return Check{
167				Name: name, When: HookPreMerge,
168				Command: `sleep 0.4; printf '{"status":"pass"}' > "$EVIDENCE_DIR/$CHECK_NAME.json"`,
169			}
170		}
171		checks := []Check{mk("a"), mk("b"), mk("c")}
172		start := time.Now()
173		results, err := Run(context.Background(), checks, ictx)
174		elapsed := time.Since(start).Milliseconds()
175		if err != nil {
176			t.Fatal(err)
177		}
178		if len(results) != 3 {
179			t.Fatalf("want 3 results, got %d", len(results))
180		}
181		// Sequential would be ~1.2s; parallel should be well under 1s.
182		if elapsed > 1000 {
183			t.Fatalf("checks ran sequentially? elapsed=%dms", elapsed)
184		}
185	}
